     1→/**
     2→ * Session Repository (T044) - Prisma Implementation
     3→ *
     4→ * Repository pattern for session lifecycle management, performance tracking,
     5→ * and analytics queries using Prisma ORM.
     6→ *
     7→ * Separation of Concerns from T043 ClassificationRepository:
     8→ * - T043: Write-heavy classification persistence (commands)
     9→ * - T044: Read-heavy session analytics and lifecycle management (queries)
    10→ *
    11→ * Key Responsibilities:
    12→ * - Session lifecycle management (create, update progress, complete, abort)
    13→ * - Batch processing support (multi-email sessions)
    14→ * - Performance metrics tracking
    15→ * - Error logging and retrieval
    16→ * - Analytics queries (by ID, status, date range, average times, failure rates)
    17→ */
    18→
    19→import { PrismaClient, Prisma } from '@prisma/client';
    20→import {
    21→  BatchSessionConfig,
    22→  ProgressUpdate,
    23→  SessionSummary,
    24→  EmailResult,
    25→  SessionDetails,
    26→  SessionStatus,
    27→  PerformanceMetrics,
    28→  BatchProgress,
    29→  SessionError,
    30→  DateRange,
    31→} from '../types/session-types';
    32→
    33→/**
    34→ * Session Repository using Prisma ORM
    35→ *
    36→ * Provides session lifecycle management with performance tracking,
    37→ * batch progress monitoring, and analytics queries.
    38→ */
    39→export class SessionRepository {
    40→  private readonly prisma: PrismaClient;
    41→  private readonly ownsPrisma: boolean;
    42→
    43→  /**
    44→   * Initialize session repository
    45→   *
    46→   * @param prisma - Optional Prisma client instance (creates default if not provided)
    47→   */
    48→  constructor(prisma?: PrismaClient) {
    49→    if (prisma) {
    50→      this.prisma = prisma;
    51→      this.ownsPrisma = false;
    52→    } else {
    53→      this.prisma = new PrismaClient();
    54→      this.ownsPrisma = true;
    55→    }
    56→  }
    57→
    58→  /**
    59→   * Create a new batch session with performance tracking
    60→   *
    61→   * Creates both the session record and associated metrics in a transaction.
    62→   * Supports multi-email batch processing.
    63→   *
    64→   * @param config - Batch session configuration
    65→   * @returns Session ID as string (safe representation of bigint)
    66→   * @throws {Error} If session creation fails
    67→   */
    68→  async createBatchSession(config: BatchSessionConfig): Promise<string> {
    69→    try {
    70→      const result = await this.prisma.$transaction(async (tx) => {
    71→        // Create session record
    72→        const session = await tx.classificationSession.create({
    73→          data: {
    74→            gmailId: config.gmailId,
    75→            pipelineVersion: config.pipelineVersion,
    76→            startedAt: new Date(),
    77→            status: 'in_progress',
    78→            triggeredBy: config.triggeredBy || 'system',
    79→            aiRoutingUsed: false,
    80→          },
    81→        });
    82→
    83→        // Create metrics record
    84→        await tx.classificationSessionMetrics.create({
    85→          data: {
    86→            sessionId: session.sessionId,
    87→            emailCount: config.batchSize,
    88→            successCount: 0,
    89→            errorCount: 0,
    90→            processingMode: config.processingMode,
    91→            batchSize: config.batchSize,
    92→          },
    93→        });
    94→
    95→        return session.sessionId.toString();
    96→      });
    97→
    98→      return result;
    99→    } catch (error) {
   100→      throw new Error(`Failed to create batch session: ${error instanceof Error ? error.message : String(error)}`);
   101→    }
   102→  }
   103→
   104→  /**
   105→   * Update session progress with atomic increments
   106→   *
   107→   * Increments success/error counts and other metrics atomically.
   108→   * Safe for concurrent updates from parallel processing.
   109→   *
   110→   * @param sessionId - Session identifier as string
   111→   * @param update - Progress update with incremental values
   112→   * @throws {Error} If update fails or session not found
   113→   */
   114→  async updateSessionProgress(sessionId: string, update: ProgressUpdate): Promise<void> {
   115→    try {
   116→      const dbSessionId = BigInt(sessionId);
   117→
   118→      // Build update data with atomic increments using proper Prisma type
   119→      const updateData: Prisma.ClassificationSessionMetricsUpdateInput = {
   120→        updatedAt: new Date(),
   121→      };
   122→
   123→      if (update.successCount !== undefined) {
   124→        updateData.successCount = { increment: update.successCount };
   125→      }
   126→      if (update.errorCount !== undefined) {
   127→        updateData.errorCount = { increment: update.errorCount };
   128→      }
   129→      if (update.parallelStagesCount !== undefined) {
   130→        updateData.parallelStagesCount = { increment: update.parallelStagesCount };
   131→      }
   132→      if (update.databaseBatchOps !== undefined) {
   133→        updateData.databaseBatchOps = { increment: update.databaseBatchOps };
   134→      }
   135→
   136→      await this.prisma.classificationSessionMetrics.update({
   137→        where: { sessionId: dbSessionId },
   138→        data: updateData,
   139→      });
   140→    } catch (error) {
   141→      throw new Error(
   142→        `Failed to update session progress for ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   143→      );
   144→    }
   145→  }
   146→
   147→  /**
   148→   * Complete a session with final performance metrics
   149→   *
   150→   * Updates session status to 'completed' and stores final performance metrics.
   151→   * Uses transaction to ensure both session and metrics are updated atomically.
   152→   *
   153→   * @param sessionId - Session identifier as string
   154→   * @param summary - Session summary with performance metrics
   155→   * @throws {Error} If completion fails
   156→   */
   157→  async completeSession(sessionId: string, summary: SessionSummary): Promise<void> {
   158→    try {
   159→      const dbSessionId = BigInt(sessionId);
   160→
   161→      await this.prisma.$transaction(async (tx) => {
   162→        // Update session record
   163→        await tx.classificationSession.update({
   164→          where: { sessionId: dbSessionId },
   165→          data: {
   166→            completedAt: new Date(),
   167→            status: 'completed',
   168→            finalCategoryId: summary.finalCategoryId || null,
   169→            finalConfidence: summary.finalConfidence ? new Prisma.Decimal(summary.finalConfidence) : null,
   170→            finalRationale: summary.finalRationale || null,
   171→          },
   172→        });
   173→
   174→        // Update metrics record
   175→        await tx.classificationSessionMetrics.update({
   176→          where: { sessionId: dbSessionId },
   177→          data: {
   178→            totalDurationMs: summary.totalDurationMs,
   179→            avgEmailDurationMs: summary.avgEmailDurationMs ? new Prisma.Decimal(summary.avgEmailDurationMs) : null,
   180→            peakMemoryMb: summary.peakMemoryMb ? new Prisma.Decimal(summary.peakMemoryMb) : null,
   181→            updatedAt: new Date(),
   182→          },
   183→        });
   184→      });
   185→    } catch (error) {
   186→      throw new Error(
   187→        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   188→      );
   189→    }
   190→  }
   191→
   192→  /**
   193→   * Abort a session with reason
   194→   *
   195→   * Marks session as 'aborted' and records the reason.
   196→   *
   197→   * @param sessionId - Session identifier as string
   198→   * @param reason - Reason for aborting
   199→   * @throws {Error} If abort fails
   200→   */
   201→  async abortSession(sessionId: string, reason: string): Promise<void> {
   202→    try {
   203→      const dbSessionId = BigInt(sessionId);
   204→
   205→      await this.prisma.classificationSession.update({
   206→        where: { sessionId: dbSessionId },
   207→        data: {
   208→          status: 'aborted',
   209→          finalRationale: reason,
   210→          completedAt: new Date(),
   211→        },
   212→      });
   213→    } catch (error) {
   214→      throw new Error(
   215→        `Failed to abort session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   216→      );
   217→    }
   218→  }
   219→
   220→  /**
   221→   * Record result for individual email in batch
   222→   *
   223→   * Increments success/error counts and logs errors for failed emails.
   224→   * Uses transaction to ensure atomic updates.
   225→   *
   226→   * @param sessionId - Session identifier as string
   227→   * @param emailId - Email identifier
   228→   * @param result - Email processing result
   229→   * @throws {Error} If recording fails
   230→   */
   231→  async recordEmailResult(sessionId: string, emailId: string, result: EmailResult): Promise<void> {
   232→    try {
   233→      const dbSessionId = BigInt(sessionId);
   234→
   235→      await this.prisma.$transaction(async (tx) => {
   236→        // Update metrics
   237→        if (result.success) {
   238→          await tx.classificationSessionMetrics.update({
   239→            where: { sessionId: dbSessionId },
   240→            data: {
   241→              successCount: { increment: 1 },
   242→              updatedAt: new Date(),
   243→            },
   244→          });
   245→        } else {
   246→          // Increment error count
   247→          await tx.classificationSessionMetrics.update({
   248→            where: { sessionId: dbSessionId },
   249→            data: {
   250→              errorCount: { increment: 1 },
   251→              updatedAt: new Date(),
   252→            },
   253→          });
   254→
   255→          // Log error
   256→          if (result.error) {
   257→            await tx.classificationSessionError.create({
   258→              data: {
   259→                sessionId: dbSessionId,
   260→                emailId: emailId,
   261→                errorType: result.error.type,
   262→                errorMessage: result.error.message,
   263→                stackTrace: result.error.stackTrace || null,
   264→              },
   265→            });
   266→          }
   267→        }
   268→      });
   269→    } catch (error) {
   270→      throw new Error(
   271→        `Failed to record email result for ${emailId}: ${error instanceof Error ? error.message : String(error)}`
   272→      );
   273→    }
   274→  }
   275→
   276→  /**
   277→   * Get batch progress for a session
   278→   *
   279→   * Calculates progress percentage and completion status.
   280→   * Optimized to use single query instead of separate metrics + session queries.
   281→   *
   282→   * @param sessionId - Session identifier as string
   283→   * @returns Batch progress summary
   284→   * @throws {Error} If session not found
   285→   */
   286→  async getBatchProgress(sessionId: string): Promise<BatchProgress> {
   287→    const dbSessionId = BigInt(sessionId);
   288→
   289→    // Optimized: Single query with include instead of two separate queries
   290→    const session = await this.prisma.classificationSession.findUnique({
   291→      where: { sessionId: dbSessionId },
   292→      include: { metrics: true },
   293→    });
   294→
   295→    if (!session || !session.metrics) {
   296→      throw new Error(`Session not found: ${sessionId}`);
   297→    }
   298→
   299→    const metrics = session.metrics;
   300→    const totalProcessed = metrics.successCount + metrics.errorCount;
   301→    const progressPercentage = metrics.emailCount > 0 ? Math.round((totalProcessed / metrics.emailCount) * 100) : 0;
   302→
   303→    return {
   304→      sessionId: sessionId,
   305→      totalEmails: metrics.emailCount,
   306→      successCount: metrics.successCount,
   307→      errorCount: metrics.errorCount,
   308→      progressPercentage: progressPercentage,
   309→      isComplete: session.status === 'completed' || session.status === 'aborted',
   310→      status: session.status as SessionStatus,
   311→    };
   312→  }
   313→
   314→  /**
   315→   * Find session by ID with full details including metrics
   316→   *
   317→   * @param sessionId - Session identifier as string
   318→   * @returns Session details with metrics or null if not found
   319→   */
   320→  async findSessionById(sessionId: string): Promise<SessionDetails | null> {
   321→    const dbSessionId = BigInt(sessionId);
   322→
   323→    const session = await this.prisma.classificationSession.findUnique({
   324→      where: { sessionId: dbSessionId },
   325→      include: {
   326→        metrics: true,
   327→      },
   328→    });
   329→
   330→    if (!session) {
   331→      return null;
   332→    }
   333→
   334→    return this.mapToSessionDetails(session);
   335→  }
   336→
   337→  /**
   338→   * Find all active (in-progress) sessions
   339→   *
   340→   * @returns Array of active session summaries
   341→   */
   342→  async findActiveSessions(): Promise<SessionDetails[]> {
   343→    const sessions = await this.prisma.classificationSession.findMany({
   344→      where: { status: 'in_progress' },
   345→      orderBy: { startedAt: 'desc' },
   346→      include: {
   347→        metrics: true,
   348→      },
   349→    });
   350→
   351→    return sessions.map((s) => this.mapToSessionDetails(s));
   352→  }
   353→
   354→  /**
   355→   * Find sessions by status
   356→   *
   357→   * @param status - Session status to filter by
   358→   * @returns Array of sessions with matching status
   359→   */
   360→  async findSessionsByStatus(status: SessionStatus): Promise<SessionDetails[]> {
   361→    const sessions = await this.prisma.classificationSession.findMany({
   362→      where: { status: status },
   363→      orderBy: { startedAt: 'desc' },
   364→      include: {
   365→        metrics: true,
   366→      },
   367→    });
   368→
   369→    return sessions.map((s) => this.mapToSessionDetails(s));
   370→  }
   371→
   372→  /**
   373→   * Find sessions within date range
   374→   *
   375→   * @param dateRange - Start and end dates (inclusive)
   376→   * @returns Array of sessions in date range
   377→   */
   378→  async findSessionsByDateRange(dateRange: DateRange): Promise<SessionDetails[]> {
   379→    const sessions = await this.prisma.classificationSession.findMany({
   380→      where: {
   381→        startedAt: {
   382→          gte: dateRange.start,
   383→          lte: dateRange.end,
   384→        },
   385→      },
   386→      orderBy: { startedAt: 'desc' },
   387→      include: {
   388→        metrics: true,
   389→      },
   390→    });
   391→
   392→    return sessions.map((s) => this.mapToSessionDetails(s));
   393→  }
   394→
   395→  /**
   396→   * Get performance metrics for a session
   397→   *
   398→   * @param sessionId - Session identifier as string
   399→   * @returns Performance metrics
   400→   * @throws {Error} If metrics not found
   401→   */
   402→  async getSessionPerformanceStats(sessionId: string): Promise<PerformanceMetrics> {
   403→    const dbSessionId = BigInt(sessionId);
   404→
   405→    const metrics = await this.prisma.classificationSessionMetrics.findUnique({
   406→      where: { sessionId: dbSessionId },
   407→    });
   408→
   409→    if (!metrics) {
   410→      throw new Error(`Session metrics not found for session: ${sessionId}`);
   411→    }
   412→
   413→    return {
   414→      emailCount: metrics.emailCount,
   415→      successCount: metrics.successCount,
   416→      errorCount: metrics.errorCount,
   417→      processingMode: metrics.processingMode as 'sequential' | 'parallel' | 'batch' | null,
   418→      batchSize: metrics.batchSize,
   419→      totalDurationMs: metrics.totalDurationMs,
   420→      avgEmailDurationMs: metrics.avgEmailDurationMs ? metrics.avgEmailDurationMs.toNumber() : null,
   421→      parallelStagesCount: metrics.parallelStagesCount,
   422→      databaseBatchOps: metrics.databaseBatchOps,
   423→      peakMemoryMb: metrics.peakMemoryMb ? metrics.peakMemoryMb.toNumber() : null,
   424→      createdAt: metrics.createdAt,
   425→      updatedAt: metrics.updatedAt,
   426→    };
   427→  }
   428→
   429→  /**
   430→   * Calculate average processing time across sessions in date range
   431→   *
   432→   * @param dateRange - Start and end dates (inclusive)
   433→   * @returns Average email processing time in milliseconds
   434→   */
   435→  async getAverageProcessingTime(dateRange: DateRange): Promise<number> {
   436→    const sessions = await this.prisma.classificationSession.findMany({
   437→      where: {
   438→        startedAt: {
   439→          gte: dateRange.start,
   440→          lte: dateRange.end,
   441→        },
   442→      },
   443→      include: {
   444→        metrics: true,
   445→      },
   446→    });
   447→
   448→    if (sessions.length === 0) {
   449→      return 0;
   450→    }
   451→
   452→    const avgTimes = sessions
   453→      .map((s) => s.metrics?.avgEmailDurationMs?.toNumber())
   454→      .filter((time): time is number => time !== undefined && time !== null);
   455→
   456→    if (avgTimes.length === 0) {
   457→      return 0;
   458→    }
   459→
   460→    const sum = avgTimes.reduce((acc, time) => acc + time, 0);
   461→    return sum / avgTimes.length;
   462→  }
   463→
   464→  /**
   465→   * Calculate failure rate across sessions in date range
   466→   *
   467→   * @param dateRange - Start and end dates (inclusive)
   468→   * @returns Failure rate as percentage (0-100)
   469→   */
   470→  async getFailureRate(dateRange: DateRange): Promise<number> {
   471→    const sessions = await this.prisma.classificationSession.findMany({
   472→      where: {
   473→        startedAt: {
   474→          gte: dateRange.start,
   475→          lte: dateRange.end,
   476→        },
   477→      },
   478→      include: {
   479→        metrics: true,
   480→      },
   481→    });
   482→
   483→    if (sessions.length === 0) {
   484→      return 0;
   485→    }
   486→
   487→    let totalEmails = 0;
   488→    let totalErrors = 0;
   489→
   490→    for (const session of sessions) {
   491→      if (session.metrics) {
   492→        totalEmails += session.metrics.emailCount;
   493→        totalErrors += session.metrics.errorCount;
   494→      }
   495→    }
   496→
   497→    if (totalEmails === 0) {
   498→      return 0;
   499→    }
   500→
   501→    return (totalErrors / totalEmails) * 100;
   502→  }
   503→
   504→  /**
   505→   * Get all errors for a session
   506→   *
   507→   * @param sessionId - Session identifier as string
   508→   * @returns Array of session errors
   509→   */
   510→  async getSessionErrors(sessionId: string): Promise<SessionError[]> {
   511→    const dbSessionId = BigInt(sessionId);
   512→
   513→    const errors = await this.prisma.classificationSessionError.findMany({
   514→      where: { sessionId: dbSessionId },
   515→      orderBy: { occurredAt: 'desc' },
   516→    });
   517→
   518→    return errors.map((e) => ({
   519→      errorId: e.errorId.toString(),
   520→      sessionId: e.sessionId.toString(),
   521→      emailId: e.emailId,
   522→      errorType: e.errorType,
   523→      errorMessage: e.errorMessage,
   524→      stackTrace: e.stackTrace,
   525→      occurredAt: e.occurredAt,
   526→    }));
   527→  }
   528→
   529→  /**
   530→   * Map Prisma session record to SessionDetails type
   531→   *
   532→   * @param session - Prisma session record with metrics
   533→   * @returns SessionDetails object
   534→   */
   535→  private mapToSessionDetails(
   536→    session: Prisma.ClassificationSessionGetPayload<{
   537→      include: { metrics: true };
   538→    }>
   539→  ): SessionDetails {
   540→    return {
   541→      sessionId: session.sessionId.toString(),
   542→      gmailId: session.gmailId,
   543→      pipelineVersion: session.pipelineVersion,
   544→      startedAt: session.startedAt,
   545→      completedAt: session.completedAt,
   546→      status: session.status as SessionStatus,
   547→      triggeredBy: session.triggeredBy,
   548→      aiRoutingUsed: session.aiRoutingUsed,
   549→      finalCategoryId: session.finalCategoryId,
   550→      finalConfidence: session.finalConfidence ? session.finalConfidence.toNumber() : null,
   551→      finalRationale: session.finalRationale,
   552→      metrics: session.metrics
   553→        ? {
   554→            emailCount: session.metrics.emailCount,
   555→            successCount: session.metrics.successCount,
   556→            errorCount: session.metrics.errorCount,
   557→            processingMode: session.metrics.processingMode as 'sequential' | 'parallel' | 'batch' | null,
   558→            batchSize: session.metrics.batchSize,
   559→            totalDurationMs: session.metrics.totalDurationMs,
   560→            avgEmailDurationMs: session.metrics.avgEmailDurationMs
   561→              ? session.metrics.avgEmailDurationMs.toNumber()
   562→              : null,
   563→            parallelStagesCount: session.metrics.parallelStagesCount,
   564→            databaseBatchOps: session.metrics.databaseBatchOps,
   565→            peakMemoryMb: session.metrics.peakMemoryMb ? session.metrics.peakMemoryMb.toNumber() : null,
   566→            createdAt: session.metrics.createdAt,
   567→            updatedAt: session.metrics.updatedAt,
   568→          }
   569→        : null,
   570→    };
   571→  }
   572→
   573→  /**
   574→   * Close the Prisma client connection
   575→   *
   576→   * Only closes if using default Prisma instance (not externally provided).
   577→   */
   578→  async close(): Promise<void> {
   579→    if (this.ownsPrisma) {
   580→      await this.prisma.$disconnect();
   581→    }
   582→  }
   583→}
