     2→ * Classification Results Persistence Layer (T043) - Prisma Implementation
     3→ *
     4→ * Repository pattern for classification results persistence using Prisma ORM:
     5→ * - Classification session management (create, update, complete)
     6→ * - Classification results with explainability traces
     7→ * - Score breakdown persistence
     8→ * - Attribute context storage
     9→ * - Multi-label classification support
    10→ * - Domain signal resolutions
    11→ * - Transaction-safe batch operations
    12→ *
    13→ * Benefits of Prisma ORM:
    14→ * - Type-safe database queries with auto-generated types
    15→ * - Built-in transaction handling for complex multi-table operations
    16→ * - Automatic JSON serialization/deserialization for explainability data
    17→ * - Connection pooling and query optimization
    18→ * - SQL injection protection via parameterized queries
    19→ */
    20→
    21→import { PrismaClient, Prisma } from '@prisma/client';
    22→import { ClassificationResult, ClassificationSession, AttributeContext } from '@gmail-automation/classification-engine';
    23→
    24→/**
    25→ * Domain signal resolution data structure
    26→ */
    27→export interface DomainSignalData {
    28→  domain: string;
    29→  signalType: 'hard_assertion' | 'strong_indicator' | 'weak_signal';
    30→  matchedCategoryId: number | null;
    31→  confidenceLevel?: string;
    32→  domainType?: string;
    33→}
    34→
    35→/**
    36→ * Classification Repository using Prisma ORM
    37→ *
    38→ * Provides type-safe classification results persistence with automatic transaction
    39→ * handling, connection pooling, and explainability trace integrity.
    40→ */
    41→export class ClassificationRepository {
    42→  private readonly prisma: PrismaClient;
    43→  private readonly ownsPrisma: boolean;
    44→  private categoryCache: Map<string, number> | null = null;
    45→
    46→  /**
    47→   * Initialize classification repository
    48→   *
    49→   * @param prisma - Optional Prisma client instance (creates default if not provided)
    50→   */
    51→  constructor(prisma?: PrismaClient) {
    52→    if (prisma) {
    53→      this.prisma = prisma;
    54→      this.ownsPrisma = false;
    55→    } else {
    56→      this.prisma = new PrismaClient();
    57→      this.ownsPrisma = true;
    58→    }
    59→  }
    60→
    61→  /**
    62→   * Initialize category cache from database
    63→   *
    64→   * Loads all active categories into memory for fast lookup by code.
    65→   * Called automatically on first use of getCategoryIdFromCode().
    66→   *
    67→   * @throws {Error} If category loading fails
    68→   */
    69→  private async initializeCategoryCache(): Promise<void> {
    70→    try {
    71→      const categories = await this.prisma.category.findMany({
    72→        where: { active: true },
    73→        select: { code: true, categoryId: true },
    74→      });
    75→
    76→      this.categoryCache = new Map(categories.map((cat) => [cat.code, cat.categoryId]));
    77→    } catch (error) {
    78→      throw new Error(`Failed to load category cache: ${error instanceof Error ? error.message : String(error)}`);
    79→    }
    80→  }
    81→
    82→  /**
    83→   * Create a new classification session
    84→   *
    85→   * @param session - ClassificationSession object
    86→   * @param gmailId - Gmail message ID being classified
    87→   * @returns Database session ID as string (safe representation of bigint)
    88→   * @throws {Error} If session creation fails
    89→   */
    90→  async createSession(session: ClassificationSession, gmailId: string): Promise<string> {
    91→    try {
    92→      const result = await this.prisma.classificationSession.create({
    93→        data: {
    94→          gmailId: gmailId,
    95→          pipelineVersion: session.configVersion,
    96→          startedAt: session.startedAt,
    97→          status: 'in_progress',
    98→          triggeredBy: 'system',
    99→          aiRoutingUsed: false,
   100→        },
   101→      });
   102→
   103→      return result.sessionId.toString();
   104→    } catch (error) {
   105→      throw new Error(
   106→        `Failed to create classification session: ${error instanceof Error ? error.message : String(error)}`
   107→      );
   108→    }
   109→  }
   110→
   111→  /**
   112→   * Complete a classification session
   113→   *
   114→   * @param sessionId - Session identifier as string (from createSession)
   115→   * @param finalCategoryId - Final category ID selected
   116→   * @param confidence - Final confidence score
   117→   * @param rationale - Final decision rationale
   118→   * @throws {Error} If session update fails
   119→   */
   120→  async completeSession(
   121→    sessionId: string,
   122→    finalCategoryId: number,
   123→    confidence: number,
   124→    rationale: string
   125→  ): Promise<void> {
   126→    try {
   127→      // Convert string session ID to BigInt for database query
   128→      const dbSessionId = BigInt(sessionId);
   129→
   130→      await this.prisma.classificationSession.update({
   131→        where: { sessionId: dbSessionId },
   132→        data: {
   133→          completedAt: new Date(),
   134→          finalCategoryId: finalCategoryId,
   135→          finalConfidence: new Prisma.Decimal(confidence),
   136→          finalRationale: rationale,
   137→          status: 'completed',
   138→        },
   139→      });
   140→    } catch (error) {
   141→      throw new Error(
   142→        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   143→      );
   144→    }
   145→  }
   146→
   147→  /**
   148→   * Save complete classification result with explainability trace
   149→   *
   150→   * Uses Prisma transaction to ensure atomicity across multiple tables:
   151→   * - classification_stage (10 pipeline stages)
   152→   * - stage_category_eval (per-category evaluations)
   153→   * - session_categories (multi-label support)
   154→   * - detected_attributes (attribute context)
   155→   * - extracted_features (AI feature extraction data, if AI was used)
   156→   * - domain_signal_resolutions (domain signals)
   157→   *
   158→   * @param result - ClassificationResult with explainability trace
   159→   * @param sessionId - Session identifier as string (from createSession)
   160→   * @throws {Error} If save fails (rolls back entire transaction)
   161→   */
   162→  async saveClassificationResult(result: ClassificationResult, sessionId: string): Promise<void> {
   163→    try {
   164→      const dbSessionId = BigInt(sessionId);
   165→
   166→      await this.prisma.$transaction(async (tx) => {
   167→        await this.saveClassificationResultInTransaction(tx, result, dbSessionId);
   168→      });
   169→    } catch (error) {
   170→      throw new Error(
   171→        `Failed to save classification result for email ${result.emailId}: ${error instanceof Error ? error.message : String(error)}`
   172→      );
   173→    }
   174→  }
   175→
   176→  /**
   177→   * Internal method to save classification result within a transaction
   178→   *
   179→   * Extracted to allow both single and batch saves to share the same logic
   180→   * while maintaining proper transaction boundaries.
   181→   *
   182→   * @param tx - Prisma transaction client
   183→   * @param result - ClassificationResult with explainability trace
   184→   * @param sessionId - Session identifier as bigint
   185→   * @throws {Error} If save fails (caller should handle)
   186→   */
   187→  private async saveClassificationResultInTransaction(
   188→    tx: Prisma.TransactionClient,
   189→    result: ClassificationResult,
   190→    sessionId: bigint
   191→  ): Promise<void> {
   192→    // 1. Create classification stages (10 pipeline stages: hard assertions through action determination)
   193→    const stageData = this.buildStageData(result, sessionId);
   194→    let stageRecords: Array<{ stageId: bigint; stageOrder: number }> = [];
   195→    if (stageData.length > 0) {
   196→      await tx.classificationStage.createMany({ data: stageData });
   197→
   198→      // Retrieve created stage records to get stage IDs for AI feature extraction
   199→      stageRecords = await tx.classificationStage.findMany({
   200→        where: { sessionId: sessionId },
   201→        select: { stageId: true, stageOrder: true },
   202→        orderBy: { stageOrder: 'asc' },
   203→      });
   204→    }
   205→
   206→    // 2. Create stage category evaluations (score breakdown for each category)
   207→    const categoryEvalData = await this.buildCategoryEvalData(result, sessionId);
   208→    if (categoryEvalData.length > 0) {
   209→      await tx.stageCategoryEval.createMany({ data: categoryEvalData });
   210→    }
   211→
   212→    // 3. Create session categories (multi-label support)
   213→    const sessionCategoryData = await this.buildSessionCategoryData(result, sessionId);
   214→    if (sessionCategoryData.length > 0) {
   215→      await tx.sessionCategory.createMany({ data: sessionCategoryData });
   216→    }
   217→
   218→    // 4. Create detected attributes (attribute context)
   219→    const attributeData = this.buildAttributeData(result.attributeContext, sessionId);
   220→    if (attributeData.length > 0) {
   221→      await tx.detectedAttribute.createMany({ data: attributeData });
   222→    }
   223→
   224→    // 5. Create extracted features (AI feature extraction data)
   225→    // Only persist if AI routing was used and we have feature extraction data
   226→    if (result.aiRoutingUsed && stageRecords.length > 0) {
   227→      const extractedFeatureData = this.buildExtractedFeatureData(result, stageRecords);
   228→      if (extractedFeatureData.length > 0) {
   229→        await tx.extractedFeature.createMany({ data: extractedFeatureData });
   230→      }
   231→    }
   232→  }
   233→
   234→  /**
   235→   * Save attribute context separately
   236→   *
   237→   * @param context - AttributeContext with detected attributes
   238→   * @param sessionId - Session identifier as string (from createSession)
   239→   * @throws {Error} If save fails
   240→   */
   241→  async saveAttributeContext(context: AttributeContext, sessionId: string): Promise<void> {
   242→    try {
   243→      const dbSessionId = BigInt(sessionId);
   244→      const attributeData = this.buildAttributeData(context, dbSessionId);
   245→      if (attributeData.length > 0) {
   246→        await this.prisma.detectedAttribute.createMany({ data: attributeData });
   247→      }
   248→    } catch (error) {
   249→      throw new Error(`Failed to save attribute context: ${error instanceof Error ? error.message : String(error)}`);
   250→    }
   251→  }
   252→
   253→  /**
   254→   * Save domain signal resolutions
   255→   *
   256→   * @param signals - Array of domain signal resolutions
   257→   * @param sessionId - Session identifier as string (from createSession)
   258→   * @throws {Error} If save fails
   259→   */
   260→  async saveDomainSignals(signals: DomainSignalData[], sessionId: string): Promise<void> {
   261→    if (signals.length === 0) {
   262→      return;
   263→    }
   264→
   265→    try {
   266→      const dbSessionId = BigInt(sessionId);
   267→      await this.prisma.domainSignalResolution.createMany({
   268→        data: signals.map((signal) => ({
   269→          sessionId: dbSessionId,
   270→          domain: signal.domain,
   271→          signalType: signal.signalType,
   272→          matchedCategoryId: signal.matchedCategoryId,
   273→          confidenceLevel: signal.confidenceLevel || null,
   274→          domainType: signal.domainType || null,
   275→          createdAt: new Date(),
   276→        })),
   277→      });
   278→    } catch (error) {
   279→      throw new Error(`Failed to save domain signals: ${error instanceof Error ? error.message : String(error)}`);
   280→    }
   281→  }
   282→
   283→  /**
   284→   * Batch save multiple classification results
   285→   *
   286→   * Wraps all saves in a single outer transaction for atomicity.
   287→   * Either all results are saved or none are (all-or-nothing semantics).
   288→   *
   289→   * @param results - Array of ClassificationResult objects
   290→   * @param sessionId - Session identifier as string (from createSession)
   291→   * @throws {Error} If batch save fails (entire batch is rolled back)
   292→   */
   293→  async batchSaveResults(results: ClassificationResult[], sessionId: string): Promise<void> {
   294→    if (results.length === 0) {
   295→      return;
   296→    }
   297→
   298→    try {
   299→      const dbSessionId = BigInt(sessionId);
   300→
   301→      // Wrap entire batch in outer transaction for atomicity (T043.5)
   302→      await this.prisma.$transaction(async (tx) => {
   303→        for (const result of results) {
   304→          await this.saveClassificationResultInTransaction(tx, result, dbSessionId);
   305→        }
   306→      });
   307→    } catch (error) {
   308→      throw new Error(
   309→        `Failed to batch save classification results: ${error instanceof Error ? error.message : String(error)}`
   310→      );
   311→    }
   312→  }
   313→
   314→  /**
   315→   * Build classification stage data from explainability trace
   316→   */
   317→  private buildStageData(
   318→    result: ClassificationResult,
   319→    sessionId: bigint
   320→  ): Array<Prisma.ClassificationStageCreateManyInput> {
   321→    const stages: Array<Prisma.ClassificationStageCreateManyInput> = [];
   322→    const trace = result.explainabilityTrace;
   323→
   324→    // Map pipeline stages to database records
   325→    const stageMapping = [
   326→      { order: 1, type: 'hard_assertions', data: trace.hardAssertions },
   327→      { order: 2, type: 'strong_indicators', data: trace.strongIndicators },
   328→      { order: 3, type: 'rule_scoring', data: trace.ruleScoring },
   329→      { order: 4, type: 'attribute_detection', data: trace.attributeDetection },
   330→      { order: 5, type: 'attribute_influence', data: trace.attributeInfluence },
   331→      { order: 6, type: 'disambiguation', data: trace.disambiguation },
   332→      { order: 7, type: 'multi_label_selection', data: trace.multiLabelSelection },
   333→      { order: 8, type: 'ai_routing', data: trace.aiRouting },
   334→      { order: 9, type: 'final_decision', data: { reason: trace.finalDecisionReason } },
   335→      {
   336→        order: 10,
   337→        type: 'action_determination',
   338→        data: {
   339→          determinedActions: result.determinedActions || [],
   340→          actionReasoning: result.finalClassificationSummary?.determinedActions
   341→            ? `Actions: ${result.finalClassificationSummary.determinedActions.join(', ')}`
   342→            : 'No actions determined',
   343→        },
   344→      },
   345→    ];
   346→
   347→    for (const stage of stageMapping) {
   348→      stages.push({
   349→        sessionId: sessionId,
   350→        stageOrder: stage.order,
   351→        stageType: stage.type,
   352→        startedAt: new Date(),
   353→        endedAt: new Date(),
   354→        features: stage.data as Prisma.InputJsonValue,
   355→        keywords: [],
   356→        passedToNext: true,
   357→      });
   358→    }
   359→
   360→    return stages;
   361→  }
   362→
   363→  /**
   364→   * Build stage category evaluation data from score breakdown
   365→   */
   366→  private async buildCategoryEvalData(
   367→    result: ClassificationResult,
   368→    sessionId: bigint
   369→  ): Promise<Array<Prisma.StageCategoryEvalCreateManyInput>> {
   370→    const evaluations: Array<Prisma.StageCategoryEvalCreateManyInput> = [];
   371→    const scoreBreakdown = result.scoreBreakdown;
   372→
   373→    // Extract category scores and create evaluations
   374→    for (const [category, scores] of Object.entries(scoreBreakdown.categoryScores || {})) {
   375→      try {
   376→        const categoryId = await this.getCategoryIdFromCode(category);
   377→        evaluations.push({
   378→          stageId: sessionId, // Simplified: using session_id as stage_id for MVP
   379→          categoryId: categoryId,
   380→          decision: result.selectedLabels.some((label) => label.category === category) ? 'positive' : 'candidate',
   381→          score: scores as unknown as Prisma.InputJsonValue,
   382→          confidence: new Prisma.Decimal(scores.finalScore || 0),
   383→          scoringComponents: scores as unknown as Prisma.InputJsonValue,
   384→          keywords: [],
   385→          createdAt: new Date(),
   386→        });
   387→      } catch (error) {
   388→        // Log warning and skip unknown category (graceful degradation)
   389→        console.warn(
   390→          `Skipping category evaluation for unknown category '${category}': ${error instanceof Error ? error.message : String(error)}`
   391→        );
   392→      }
   393→    }
   394→
   395→    return evaluations;
   396→  }
   397→
   398→  /**
   399→   * Build session category data (multi-label support)
   400→   */
   401→  private async buildSessionCategoryData(
   402→    result: ClassificationResult,
   403→    sessionId: bigint
   404→  ): Promise<Array<Prisma.SessionCategoryCreateManyInput>> {
   405→    const categories: Array<Prisma.SessionCategoryCreateManyInput> = [];
   406→
   407→    for (const label of result.selectedLabels) {
   408→      try {
   409→        const categoryId = await this.getCategoryIdFromCode(label.category);
   410→        const subtypeId = label.subtype ? await this.getCategoryIdFromCode(label.subtype) : null;
   411→
   412→        categories.push({
   413→          sessionId: sessionId,
   414→          categoryId: categoryId,
   415→          subtypeId: subtypeId,
   416→          isPrimary: label.isPrimary,
   417→          confidence: new Prisma.Decimal(label.confidence),
   418→          categoryScore: new Prisma.Decimal(label.score),
   419→          hardAssertion: false, // TODO: Extract from explainability trace
   420→          aiClassified: result.aiRoutingUsed,
   421→          scoringTrace: result.scoreBreakdown as unknown as Prisma.InputJsonValue,
   422→          labelOrder: label.labelOrder,
   423→          createdAt: new Date(),
   424→        });
   425→      } catch (error) {
   426→        // Log warning and skip unknown category (graceful degradation)
   427→        console.warn(
   428→          `Skipping session category for unknown category '${label.category}': ${error instanceof Error ? error.message : String(error)}`
   429→        );
   430→      }
   431→    }
   432→
   433→    return categories;
   434→  }
   435→
   436→  /**
   437→   * Build detected attribute data from attribute context
   438→   *
   439→   * Maps attribute context to database records with complete detection metadata,
   440→   * influence tracking, and temporal signals. Handles:
   441→   * - Urgency levels with detection metadata
   442→   * - Domain attributes with influence tracking
   443→   * - Structural patterns with evidence
   444→   * - Temporal signals (NEW: T043.4)
   445→   * - Influence applications with score impacts (NEW: T043.4)
   446→   * - Derived attributes (NEW: T043.4)
   447→   *
   448→   * @param context - AttributeContext with detected attributes and metadata
   449→   * @param sessionId - Session identifier as bigint
   450→   * @returns Array of detected attribute records for database insertion
   451→   */
   452→  private buildAttributeData(
   453→    context: AttributeContext,
   454→    sessionId: bigint
   455→  ): Array<Prisma.DetectedAttributeCreateManyInput> {
   456→    const attributes: Array<Prisma.DetectedAttributeCreateManyInput> = [];
   457→
   458→    // Helper to extract detection metadata
   459→    const getDetectionMetadata = (attributeKey: string) => {
   460→      return context.detectionMetadata?.[attributeKey];
   461→    };
   462→
   463→    // Helper to find influence applications for an attribute
   464→    const getInfluenceData = (attributeName: string) => {
   465→      const influences = context.influenceApplications?.filter((app) => app.attributeUsed === attributeName) || [];
   466→      const categoriesInfluenced = influences.map((app) => app.targetCategory);
   467→      const totalBonus = influences.reduce((sum, app) => sum + app.scoreImpact, 0);
   468→      const primaryRole = influences.length > 0 ? influences[0].roleType : 'NEUTRAL';
   469→      return { categoriesInfluenced, totalBonus, primaryRole };
   470→    };
   471→
   472→    // 1. Add urgency attribute
   473→    const urgencyMetadata = getDetectionMetadata('urgency');
   474→    const urgencyInfluence = getInfluenceData('urgency');
   475→    attributes.push({
   476→      sessionId: sessionId,
   477→      attributeName: 'urgency',
   478→      attributeValue: context.urgency,
   479→      detectionMethod: urgencyMetadata?.detectionMethod || 'rule',
   480→      detectionEvidence: urgencyMetadata?.evidence || `Urgency level: ${context.urgency}`,
   481→      influenceRole: urgencyInfluence.primaryRole,
   482→      categoriesInfluenced: urgencyInfluence.categoriesInfluenced,
   483→      totalBonusApplied: new Prisma.Decimal(urgencyInfluence.totalBonus),
   484→      createdAt: new Date(),
   485→    });
   486→
   487→    // 2. Add domain attributes
   488→    for (const domain of context.domains) {
   489→      const domainKey = `domain:${domain}`;
   490→      const domainMetadata = getDetectionMetadata(domainKey);
   491→      const domainInfluence = getInfluenceData(domainKey);
   492→
   493→      attributes.push({
   494→        sessionId: sessionId,
   495→        attributeName: domainKey,
   496→        attributeValue: domain,
   497→        detectionMethod: domainMetadata?.detectionMethod || 'domainLookup',
   498→        detectionEvidence: domainMetadata?.evidence || `Domain ${domain} detected in email`,
   499→        influenceRole: domainInfluence.primaryRole,
   500→        categoriesInfluenced: domainInfluence.categoriesInfluenced,
   501→        totalBonusApplied: new Prisma.Decimal(domainInfluence.totalBonus),
   502→        createdAt: new Date(),
   503→      });
   504→    }
   505→
   506→    // 3. Add structural pattern attributes
   507→    for (const pattern of context.structuralPatterns) {
   508→      const patternKey = `pattern:${pattern}`;
   509→      const patternMetadata = getDetectionMetadata(patternKey);
   510→      const patternInfluence = getInfluenceData(patternKey);
   511→
   512→      attributes.push({
   513→        sessionId: sessionId,
   514→        attributeName: patternKey,
   515→        attributeValue: pattern,
   516→        detectionMethod: patternMetadata?.detectionMethod || 'pattern',
   517→        detectionEvidence: patternMetadata?.evidence || `Structural pattern ${pattern} matched`,
   518→        influenceRole: patternInfluence.primaryRole,
   519→        categoriesInfluenced: patternInfluence.categoriesInfluenced,
   520→        totalBonusApplied: new Prisma.Decimal(patternInfluence.totalBonus),
   521→        createdAt: new Date(),
   522→      });
   523→    }
   524→
   525→    // 4. Add temporal signal attributes (NEW: T043.4)
   526→    for (const signal of context.temporalSignals) {
   527→      const signalKey = `temporal:${signal}`;
   528→      const signalMetadata = getDetectionMetadata(signalKey);
   529→      const signalInfluence = getInfluenceData(signalKey);
   530→
   531→      attributes.push({
   532→        sessionId: sessionId,
   533→        attributeName: signalKey,
   534→        attributeValue: signal,
   535→        detectionMethod: signalMetadata?.detectionMethod || 'temporalAnalysis',
   536→        detectionEvidence:
   537→          signalMetadata?.evidence || `Temporal signal ${signal} detected (e.g., time-sensitive keywords, deadlines)`,
   538→        influenceRole: signalInfluence.primaryRole,
   539→        categoriesInfluenced: signalInfluence.categoriesInfluenced,
   540→        totalBonusApplied: new Prisma.Decimal(signalInfluence.totalBonus),
   541→        createdAt: new Date(),
   542→      });
   543→    }
   544→
   545→    // 5. Add derived attributes (NEW: T043.4)
   546→    // Derived attributes are computed from other attributes (e.g., "is_self_sent" derived from from/to comparison)
   547→    for (const [derivedKey, derivedResult] of Object.entries(context.derivedAttributes || {})) {
   548→      const derivedInfluence = getInfluenceData(derivedKey);
   549→
   550→      attributes.push({
   551→        sessionId: sessionId,
   552→        attributeName: derivedKey,
   553→        attributeValue: String(derivedResult.calculatedValue),
   554→        detectionMethod: 'derived',
   555→        detectionEvidence: `Derived from: ${derivedResult.sourceAttributes.join(', ')} via ${derivedResult.derivationLogic}`,
   556→        influenceRole: derivedInfluence.primaryRole,
   557→        categoriesInfluenced: derivedInfluence.categoriesInfluenced,
   558→        totalBonusApplied: new Prisma.Decimal(derivedInfluence.totalBonus),
   559→        createdAt: new Date(),
   560→      });
   561→    }
   562→
   563→    // 6. Add influence applications that don't map to specific detected attributes (NEW: T043.4)
   564→    // Some influence applications may reference attributes not explicitly in the detected lists
   565→    // (e.g., attribute combinations, context-dependent influences)
   566→    const coveredAttributes = new Set([
   567→      'urgency',
   568→      ...context.domains.map((d) => `domain:${d}`),
   569→      ...context.structuralPatterns.map((p) => `pattern:${p}`),
   570→      ...context.temporalSignals.map((s) => `temporal:${s}`),
   571→      ...Object.keys(context.derivedAttributes || {}),
   572→    ]);
   573→
   574→    for (const influence of context.influenceApplications || []) {
   575→      if (!coveredAttributes.has(influence.attributeUsed)) {
   576→        // This is an influence from an attribute not explicitly tracked above
   577→        // (e.g., attribute combinations, implicit signals)
   578→        const metadata = getDetectionMetadata(influence.attributeUsed);
   579→
   580→        attributes.push({
   581→          sessionId: sessionId,
   582→          attributeName: influence.attributeUsed,
   583→          attributeValue: 'implicit', // No explicit value, inferred from influence
   584→          detectionMethod: metadata?.detectionMethod || 'derived',
   585→          detectionEvidence:
   586→            metadata?.evidence || `Implicit influence on ${influence.targetCategory}: ${influence.applicationReason}`,
   587→          influenceRole: influence.roleType,
   588→          categoriesInfluenced: [influence.targetCategory],
   589→          totalBonusApplied: new Prisma.Decimal(influence.scoreImpact),
   590→          createdAt: new Date(),
   591→        });
   592→
   593→        // Mark as covered to avoid duplicates
   594→        coveredAttributes.add(influence.attributeUsed);
   595→      }
   596→    }
   597→
   598→    return attributes;
   599→  }
   600→
   601→  /**
   602→   * Build extracted feature data from AI feature extraction results
   603→   *
   604→   * Extracts AI-generated features from the explainability trace and creates
   605→   * database records linked to the AI routing stage (stage 8).
   606→   *
   607→   * Only called when AI routing was used (result.aiRoutingUsed = true).
   608→   *
   609→   * @param result - ClassificationResult with AI feature extraction data
   610→   * @param stageRecords - Created classification stages with IDs
   611→   * @returns Array of extracted feature records for database insertion
   612→   */
   613→  private buildExtractedFeatureData(
   614→    result: ClassificationResult,
   615→    stageRecords: Array<{ stageId: bigint; stageOrder: number }>
   616→  ): Array<Prisma.ExtractedFeatureCreateManyInput> {
   617→    const features: Array<Prisma.ExtractedFeatureCreateManyInput> = [];
   618→
   619→    // Find the AI routing stage (stage 8) to associate features with
   620→    const aiRoutingStage = stageRecords.find((stage) => stage.stageOrder === 8);
   621→    if (!aiRoutingStage) {
   622→      console.warn('AI routing stage not found in stage records, skipping feature extraction persistence');
   623→      return features;
   624→    }
   625→
   626→    // Extract AI feature extraction data from explainability trace
   627→    const aiResponse = result.explainabilityTrace?.aiRouting?.aiResponse;
   628→    if (!aiResponse?.extractedFeatures) {
   629→      // No AI features to persist (AI routing may have skipped feature extraction)
   630→      return features;
   631→    }
   632→
   633→    const extractedFeatures = aiResponse.extractedFeatures as {
   634→      semanticIntent?: {
   635→        primaryPurpose?: string;
   636→        actionRequired?: string;
   637→        urgencyLevel?: string;
   638→      };
   639→      categoryEnhancements?: Record<
   640→        string,
   641→        {
   642→          applies: boolean;
   643→          confidenceBoost: number;
   644→          evidence?: {
   645→            quotedPhrases?: string[];
   646→            keywords?: string[];
   647→            reasoning?: string;
   648→          };
   649→        }
   650→      >;
   651→    };
   652→
   653→    // Extract semantic intent features
   654→    if (extractedFeatures.semanticIntent) {
   655→      const intent = extractedFeatures.semanticIntent;
   656→
   657→      if (intent.primaryPurpose) {
   658→        features.push({
   659→          stageId: aiRoutingStage.stageId,
   660→          name: 'semantic_intent_primary_purpose',
   661→          value: intent.primaryPurpose,
   662→          importance: new Prisma.Decimal(0.8), // High importance for primary purpose
   663→          evidenceSnippet: null,
   664→          createdAt: new Date(),
   665→        });
   666→      }
   667→
   668→      if (intent.actionRequired) {
   669→        features.push({
   670→          stageId: aiRoutingStage.stageId,
   671→          name: 'semantic_intent_action_required',
   672→          value: intent.actionRequired,
   673→          importance: new Prisma.Decimal(0.7),
   674→          evidenceSnippet: null,
   675→          createdAt: new Date(),
   676→        });
   677→      }
   678→
   679→      if (intent.urgencyLevel) {
   680→        features.push({
   681→          stageId: aiRoutingStage.stageId,
   682→          name: 'semantic_intent_urgency_level',
   683→          value: intent.urgencyLevel,
   684→          importance: new Prisma.Decimal(0.6),
   685→          evidenceSnippet: null,
   686→          createdAt: new Date(),
   687→        });
   688→      }
   689→    }
   690→
   691→    // Extract category enhancement features
   692→    if (extractedFeatures.categoryEnhancements) {
   693→      for (const [category, enhancement] of Object.entries(extractedFeatures.categoryEnhancements)) {
   694→        if (enhancement.applies && enhancement.confidenceBoost > 0) {
   695→          // Create a feature record for this category enhancement
   696→          const evidenceSnippet =
   697→            enhancement.evidence?.quotedPhrases && enhancement.evidence.quotedPhrases.length > 0
   698→              ? enhancement.evidence.quotedPhrases.slice(0, 3).join(' | ') // First 3 quoted phrases
   699→              : enhancement.evidence?.reasoning || null;
   700→
   701→          features.push({
   702→            stageId: aiRoutingStage.stageId,
   703→            name: `category_enhancement_${category}`,
   704→            value: `boost:${enhancement.confidenceBoost}`,
   705→            importance: new Prisma.Decimal(Math.min(enhancement.confidenceBoost / 100, 1.0)), // Normalize to 0-1
   706→            evidenceSnippet: evidenceSnippet ? evidenceSnippet.substring(0, 500) : null, // Limit length
   707→            createdAt: new Date(),
   708→          });
   709→
   710→          // If there are keywords, create a separate feature for them
   711→          if (enhancement.evidence?.keywords && enhancement.evidence.keywords.length > 0) {
   712→            features.push({
   713→              stageId: aiRoutingStage.stageId,
   714→              name: `category_keywords_${category}`,
   715→              value: enhancement.evidence.keywords.slice(0, 10).join(', '), // First 10 keywords
   716→              importance: new Prisma.Decimal(0.5),
   717→              evidenceSnippet: null,
   718→              createdAt: new Date(),
   719→            });
   720→          }
   721→        }
   722→      }
   723→    }
   724→
   725→    return features;
   726→  }
   727→
   728→  /**
   729→   * Get category ID from category code
   730→   *
   731→   * Uses cached category lookup for performance. Cache is initialized
   732→   * on first use and persists for the lifetime of the repository instance.
   733→   *
   734→   * @param code - Category code (e.g., 'finance', 'personal')
   735→   * @returns Category ID from database
   736→   * @throws {Error} If category code not found in database
   737→   */
   738→  private async getCategoryIdFromCode(code: string): Promise<number> {
   739→    // Initialize cache on first use
   740→    if (this.categoryCache === null) {
   741→      await this.initializeCategoryCache();
   742→    }
   743→
   744→    const categoryId = this.categoryCache!.get(code);
   745→    if (categoryId === undefined) {
   746→      throw new Error(
   747→        `Category code '${code}' not found in database. Available categories: ${Array.from(this.categoryCache!.keys()).join(', ')}`
   748→      );
   749→    }
   750→
   751→    return categoryId;
   752→  }
   753→
   754→  /**
   755→   * Close the Prisma client connection
   756→   *
   757→   * Only closes if using default Prisma instance (not externally provided).
   758→   */
   759→  async close(): Promise<void> {
   760→    if (this.ownsPrisma) {
   761→      await this.prisma.$disconnect();
   762→    }
   763→  }
   764→}
   765→

