     1→/**
     2→ * Session Repository (T044) - Prisma Implementation
     3→ *
     4→ * Repository pattern for session lifecycle management, performance tracking,
     5→ * and analytics queries using Prisma ORM.
     6→ *
     7→ * Separation of Concerns from T043 ClassificationRepository:
     8→ * - T043: Write-heavy classification persistence (commands)
     9→ * - T044: Read-heavy session analytics and lifecycle management (queries)
    10→ *
    11→ * Key Responsibilities:
    12→ * - Session lifecycle management (create, update progress, complete, abort)
    13→ * - Batch processing support (multi-email sessions)
    14→ * - Performance metrics tracking
    15→ * - Error logging and retrieval
    16→ * - Analytics queries (by ID, status, date range, average times, failure rates)
    17→ */
    18→
    19→import { PrismaClient, Prisma } from '@prisma/client';
    20→import {
    21→  BatchSessionConfig,
    22→  ProgressUpdate,
    23→  SessionSummary,
    24→  EmailResult,
    25→  SessionDetails,
    26→  SessionStatus,
    27→  PerformanceMetrics,
    28→  BatchProgress,
    29→  SessionError,
    30→  DateRange,
    31→} from '../types/session-types';
    32→
    33→/**
    34→ * Session Repository using Prisma ORM
    35→ *
    36→ * Provides session lifecycle management with performance tracking,
    37→ * batch progress monitoring, and analytics queries.
    38→ */
    39→export class SessionRepository {
    40→  private readonly prisma: PrismaClient;
    41→  private readonly ownsPrisma: boolean;
    42→
    43→  /**
    44→   * Initialize session repository
    45→   *
    46→   * @param prisma - Optional Prisma client instance (creates default if not provided)
    47→   */
    48→  constructor(prisma?: PrismaClient) {
    49→    if (prisma) {
    50→      this.prisma = prisma;
    51→      this.ownsPrisma = false;
    52→    } else {
    53→      this.prisma = new PrismaClient();
    54→      this.ownsPrisma = true;
    55→    }
    56→  }
    57→
    58→  /**
    59→   * Create a new batch session with performance tracking
    60→   *
    61→   * Creates both the session record and associated metrics in a transaction.
    62→   * Supports multi-email batch processing.
    63→   *
    64→   * @param config - Batch session configuration
    65→   * @returns Session ID as string (safe representation of bigint)
    66→   * @throws {Error} If session creation fails
    67→   */
    68→  async createBatchSession(config: BatchSessionConfig): Promise<string> {
    69→    try {
    70→      const result = await this.prisma.$transaction(async (tx) => {
    71→        // Create session record
    72→        const session = await tx.classificationSession.create({
    73→          data: {
    74→            gmailId: config.gmailId,
    75→            pipelineVersion: config.pipelineVersion,
    76→            startedAt: new Date(),
    77→            status: 'in_progress',
    78→            triggeredBy: config.triggeredBy || 'system',
    79→            aiRoutingUsed: false,
    80→          },
    81→        });
    82→
    83→        // Create metrics record
    84→        await tx.classificationSessionMetrics.create({
    85→          data: {
    86→            sessionId: session.sessionId,
    87→            emailCount: config.batchSize,
    88→            successCount: 0,
    89→            errorCount: 0,
    90→            processingMode: config.processingMode,
    91→            batchSize: config.batchSize,
    92→          },
    93→        });
    94→
    95→        return session.sessionId.toString();
    96→      });
    97→
    98→      return result;
    99→    } catch (error) {
   100→      throw new Error(`Failed to create batch session: ${error instanceof Error ? error.message : String(error)}`);
   101→    }
   102→  }
   103→
   104→  /**
   105→   * Update session progress with atomic increments
   106→   *
   107→   * Increments success/error counts and other metrics atomically.
   108→   * Safe for concurrent updates from parallel processing.
   109→   *
   110→   * @param sessionId - Session identifier as string
   111→   * @param update - Progress update with incremental values
   112→   * @throws {Error} If update fails or session not found
   113→   */
   114→  async updateSessionProgress(sessionId: string, update: ProgressUpdate): Promise<void> {
   115→    try {
   116→      const dbSessionId = BigInt(sessionId);
   117→
   118→      // Build update data with atomic increments using proper Prisma type
   119→      const updateData: Prisma.ClassificationSessionMetricsUpdateInput = {
   120→        updatedAt: new Date(),
   121→      };
   122→
   123→      if (update.successCount !== undefined) {
   124→        updateData.successCount = { increment: update.successCount };
   125→      }
   126→      if (update.errorCount !== undefined) {
   127→        updateData.errorCount = { increment: update.errorCount };
   128→      }
   129→      if (update.parallelStagesCount !== undefined) {
   130→        updateData.parallelStagesCount = { increment: update.parallelStagesCount };
   131→      }
   132→      if (update.databaseBatchOps !== undefined) {
   133→        updateData.databaseBatchOps = { increment: update.databaseBatchOps };
   134→      }
   135→
   136→      await this.prisma.classificationSessionMetrics.update({
   137→        where: { sessionId: dbSessionId },
   138→        data: updateData,
   139→      });
   140→    } catch (error) {
   141→      throw new Error(
   142→        `Failed to update session progress for ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   143→      );
   144→    }
   145→  }
   146→
   147→  /**
   148→   * Complete a session with final performance metrics
   149→   *
   150→   * Updates session status to 'completed' and stores final performance metrics.
   151→   * Uses transaction to ensure both session and metrics are updated atomically.
   152→   *
   153→   * @param sessionId - Session identifier as string
   154→   * @param summary - Session summary with performance metrics
   155→   * @throws {Error} If completion fails
   156→   */
   157→  async completeSession(sessionId: string, summary: SessionSummary): Promise<void> {
   158→    try {
   159→      const dbSessionId = BigInt(sessionId);
   160→
   161→      await this.prisma.$transaction(async (tx) => {
   162→        // Update session record
   163→        await tx.classificationSession.update({
   164→          where: { sessionId: dbSessionId },
   165→          data: {
   166→            completedAt: new Date(),
   167→            status: 'completed',
   168→            finalCategoryCode: summary.finalCategoryCode || null,
   169→            finalConfidence: summary.finalConfidence ? new Prisma.Decimal(summary.finalConfidence) : null,
   170→            finalRationale: summary.finalRationale || null,
   171→          },
   172→        });
   173→
   174→        // Update metrics record
   175→        await tx.classificationSessionMetrics.update({
   176→          where: { sessionId: dbSessionId },
   177→          data: {
   178→            totalDurationMs: summary.totalDurationMs,
   179→            avgEmailDurationMs: summary.avgEmailDurationMs ? new Prisma.Decimal(summary.avgEmailDurationMs) : null,
   180→            peakMemoryMb: summary.peakMemoryMb ? new Prisma.Decimal(summary.peakMemoryMb) : null,
   181→            updatedAt: new Date(),
   182→          },
   183→        });
   184→      });
   185→    } catch (error) {
   186→      throw new Error(
   187→        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   188→      );
   189→    }
   190→  }
   191→
   192→  /**
   193→   * Abort a session with reason
   194→   *
   195→   * Marks session as 'aborted' and records the reason.
   196→   *
   197→   * @param sessionId - Session identifier as string
   198→   * @param reason - Reason for aborting
   199→   * @throws {Error} If abort fails
   200→   */
   201→  async abortSession(sessionId: string, reason: string): Promise<void> {
   202→    try {
   203→      const dbSessionId = BigInt(sessionId);
   204→
   205→      await this.prisma.classificationSession.update({
   206→        where: { sessionId: dbSessionId },
   207→        data: {
   208→          status: 'aborted',
   209→          finalRationale: reason,
   210→          completedAt: new Date(),
   211→        },
   212→      });
   213→    } catch (error) {
   214→      throw new Error(
   215→        `Failed to abort session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
   216→      );
   217→    }
   218→  }
   219→
   220→  /**
   221→   * Record result for individual email in batch
   222→   *
   223→   * Increments success/error counts and logs errors for failed emails.
   224→   * Uses transaction to ensure atomic updates.
   225→   *
   226→   * @param sessionId - Session identifier as string
   227→   * @param emailId - Email identifier
   228→   * @param result - Email processing result
   229→   * @throws {Error} If recording fails
   230→   */
   231→  async recordEmailResult(sessionId: string, emailId: string, result: EmailResult): Promise<void> {
   232→    try {
   233→      const dbSessionId = BigInt(sessionId);
   234→
   235→      await this.prisma.$transaction(async (tx) => {
   236→        // Update metrics
   237→        if (result.success) {
   238→          await tx.classificationSessionMetrics.update({
   239→            where: { sessionId: dbSessionId },
   240→            data: {
   241→              successCount: { increment: 1 },
   242→              updatedAt: new Date(),
   243→            },
   244→          });
   245→        } else {
   246→          // Increment error count
   247→          await tx.classificationSessionMetrics.update({
   248→            where: { sessionId: dbSessionId },
   249→            data: {
   250→              errorCount: { increment: 1 },
   251→              updatedAt: new Date(),
   252→            },
   253→          });
   254→
   255→          // Log error
   256→          if (result.error) {
   257→            await tx.classificationSessionError.create({
   258→              data: {
   259→                sessionId: dbSessionId,
   260→                emailId: emailId,
   261→                errorType: result.error.type,
   262→                errorMessage: result.error.message,
   263→                stackTrace: result.error.stackTrace || null,
   264→              },
   265→            });
   266→          }
   267→        }
   268→      });
   269→    } catch (error) {
   270→      throw new Error(
   271→        `Failed to record email result for ${emailId}: ${error instanceof Error ? error.message : String(error)}`
   272→      );
   273→    }
   274→  }
   275→
   276→  /**
   277→   * Get batch progress for a session
   278→   *
   279→   * Calculates progress percentage and completion status.
   280→   * Optimized to use single query instead of separate metrics + session queries.
   281→   *
   282→   * @param sessionId - Session identifier as string
   283→   * @returns Batch progress summary
   284→   * @throws {Error} If session not found
   285→   */
   286→  async getBatchProgress(sessionId: string): Promise<BatchProgress> {
   287→    const dbSessionId = BigInt(sessionId);
   288→
   289→    // Optimized: Single query with include instead of two separate queries
   290→    const session = await this.prisma.classificationSession.findUnique({
   291→      where: { sessionId: dbSessionId },
   292→      include: { metrics: true },
   293→    });
   294→
   295→    if (!session || !session.metrics) {
   296→      throw new Error(`Session not found: ${sessionId}`);
   297→    }
   298→
