     1→/**
     2→ * Unit tests for SessionRepository (T044 - TDD Approach)
     3→ *
     4→ * Tests session lifecycle management, performance tracking, batch progress updates,
     5→ * analytics queries, and error logging. These tests are written FIRST before
     6→ * implementation following TDD principles.
     7→ *
     8→ * Test Strategy:
     9→ * - Mock Prisma client for unit testing
    10→ * - Test session lifecycle (create, update, complete, abort)
    11→ * - Test batch progress tracking with per-email results
    12→ * - Test query operations (by ID, status, date range)
    13→ * - Test performance metrics aggregation
    14→ * - Test error logging and retrieval
    15→ * - Test edge cases (not found, concurrent updates)
    16→ */
    17→
    18→import { SessionRepository } from '../../src/persistence/session-repository';
    19→import { PrismaClient } from '@prisma/client';
    20→import {
    21→  BatchSessionConfig,
    22→  ProgressUpdate,
    23→  SessionSummary,
    24→  EmailResult,
    25→  SessionStatus,
    26→} from '../../src/types/session-types';
    27→
    28→// Mock Prisma Client
    29→jest.mock('@prisma/client', () => {
    30→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
    31→  const mockPrismaClient: any = {
    32→    classificationSession: {
    33→      create: jest.fn(),
    34→      update: jest.fn(),
    35→      findUnique: jest.fn(),
    36→      findMany: jest.fn(),
    37→      findFirst: jest.fn(),
    38→    },
    39→    classificationSessionMetrics: {
    40→      create: jest.fn(),
    41→      update: jest.fn(),
    42→      upsert: jest.fn(),
    43→      findUnique: jest.fn(),
    44→      findMany: jest.fn(),
    45→    },
    46→    classificationSessionError: {
    47→      create: jest.fn(),
    48→      findMany: jest.fn(),
    49→      count: jest.fn(),
    50→    },
    51→    $transaction: jest.fn((callback) => callback(mockPrismaClient)),
    52→    $disconnect: jest.fn(),
    53→  };
    54→
    55→  // Mock Prisma Decimal class
    56→  class MockDecimal {
    57→    value: number;
    58→    constructor(value: number | string) {
    59→      this.value = typeof value === 'string' ? parseFloat(value) : value;
    60→    }
    61→    toString() {
    62→      return this.value.toString();
    63→    }
    64→    toNumber() {
    65→      return this.value;
    66→    }
    67→  }
    68→
    69→  return {
    70→    PrismaClient: jest.fn(() => mockPrismaClient),
    71→    Prisma: {
    72→      Decimal: MockDecimal,
    73→    },
    74→  };
    75→});
    76→
    77→describe('SessionRepository', () => {
    78→  let repository: SessionRepository;
    79→  let mockPrisma: jest.Mocked<PrismaClient>;
    80→
    81→  beforeEach(() => {
    82→    jest.clearAllMocks();
    83→    repository = new SessionRepository();
    84→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    85→    mockPrisma = (repository as any).prisma;
    86→  });
    87→
    88→  afterEach(async () => {
    89→    await repository.close();
    90→  });
    91→
    92→  describe('Session Lifecycle Management', () => {
    93→    describe('createBatchSession', () => {
    94→      it('should create a new batch session with metrics', async () => {
    95→        const config: BatchSessionConfig = {
    96→          gmailId: 'msg-batch-001',
    97→          pipelineVersion: 'v1.0.0',
    98→          processingMode: 'batch',
    99→          batchSize: 100,
   100→          triggeredBy: 'cron-job',
   101→        };
   102→
   103→        // Mock session creation
   104→        (mockPrisma.classificationSession.create as jest.Mock).mockResolvedValue({
   105→          sessionId: BigInt(1),
   106→          gmailId: config.gmailId,
   107→          pipelineVersion: config.pipelineVersion,
   108→          startedAt: new Date(),
   109→          completedAt: null,
   110→          status: 'in_progress',
   111→          triggeredBy: config.triggeredBy,
   112→        });
   113→
   114→        // Mock metrics creation
   115→        (mockPrisma.classificationSessionMetrics.create as jest.Mock).mockResolvedValue({
   116→          sessionId: BigInt(1),
   117→          emailCount: config.batchSize,
   118→          successCount: 0,
   119→          errorCount: 0,
   120→          processingMode: config.processingMode,
   121→          batchSize: config.batchSize,
   122→        });
   123→
   124→        const sessionId = await repository.createBatchSession(config);
   125→
   126→        expect(sessionId).toBe('1');
   127→        expect(mockPrisma.$transaction).toHaveBeenCalled();
   128→        expect(mockPrisma.classificationSession.create).toHaveBeenCalledWith({
   129→          data: expect.objectContaining({
   130→            gmailId: config.gmailId,
   131→            pipelineVersion: config.pipelineVersion,
   132→            status: 'in_progress',
   133→            triggeredBy: config.triggeredBy,
   134→          }),
   135→        });
   136→        expect(mockPrisma.classificationSessionMetrics.create).toHaveBeenCalledWith({
   137→          data: expect.objectContaining({
   138→            emailCount: config.batchSize,
   139→            processingMode: config.processingMode,
   140→            batchSize: config.batchSize,
   141→          }),
   142→        });
   143→      });
   144→
   145→      it('should rollback transaction if metrics creation fails', async () => {
   146→        const config: BatchSessionConfig = {
   147→          gmailId: 'msg-error',
   148→          pipelineVersion: 'v1.0.0',
   149→          processingMode: 'batch',
   150→          batchSize: 50,
   151→        };
   152→
   153→        mockPrisma.$transaction.mockRejectedValue(new Error('Metrics creation failed'));
   154→
   155→        await expect(repository.createBatchSession(config)).rejects.toThrow('Failed to create batch session');
   156→        expect(mockPrisma.$transaction).toHaveBeenCalled();
   157→      });
   158→    });
   159→
   160→    describe('updateSessionProgress', () => {
   161→      it('should increment success and error counts atomically', async () => {
   162→        const sessionId = '1';
   163→        const update: ProgressUpdate = {
   164→          successCount: 10,
   165→          errorCount: 2,
   166→        };
   167→
   168→        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockResolvedValue({
   169→          sessionId: BigInt(1),
   170→          successCount: 10,
   171→          errorCount: 2,
   172→        });
   173→
   174→        await repository.updateSessionProgress(sessionId, update);
   175→
   176→        expect(mockPrisma.classificationSessionMetrics.update).toHaveBeenCalledWith({
   177→          where: { sessionId: BigInt(1) },
   178→          data: {
   179→            successCount: { increment: 10 },
   180→            errorCount: { increment: 2 },
   181→            updatedAt: expect.any(Date),
   182→          },
   183→        });
   184→      });
   185→
   186→      it('should update parallel stages and batch ops counts', async () => {
   187→        const sessionId = '1';
   188→        const update: ProgressUpdate = {
   189→          parallelStagesCount: 5,
   190→          databaseBatchOps: 3,
   191→        };
   192→
   193→        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockResolvedValue({
   194→          sessionId: BigInt(1),
   195→          parallelStagesCount: 5,
   196→          databaseBatchOps: 3,
   197→        });
   198→
   199→        await repository.updateSessionProgress(sessionId, update);
   200→
   201→        expect(mockPrisma.classificationSessionMetrics.update).toHaveBeenCalledWith({
   202→          where: { sessionId: BigInt(1) },
   203→          data: expect.objectContaining({
   204→            parallelStagesCount: { increment: 5 },
   205→            databaseBatchOps: { increment: 3 },
   206→          }),
   207→        });
   208→      });
   209→
   210→      it('should throw error if session not found', async () => {
   211→        (mockPrisma.classificationSessionMetrics.update as jest.Mock).mockRejectedValue(new Error('Record not found'));
   212→
   213→        await expect(repository.updateSessionProgress('999', { successCount: 1 })).rejects.toThrow(
   214→          'Failed to update session progress'
   215→        );
   216→      });
   217→    });
   218→
   219→    describe('completeSession', () => {
   220→      it('should complete session with performance metrics', async () => {
   221→        const sessionId = '1';
   222→        const summary: SessionSummary = {
   223→          totalDurationMs: 45000,
   224→          avgEmailDurationMs: 450,
   225→          peakMemoryMb: 256.5,
   226→          finalCategoryCode: 'finance',
   227→          finalConfidence: 0.95,
   228→          finalRationale: 'Batch processing completed successfully',
   229→        };
   230→
   231→        // Mock transaction to succeed
   232→        mockPrisma.$transaction.mockImplementation(async (callback) => callback(mockPrisma));
   233→
   234→        (mockPrisma.classificationSession.update as jest.Mock).mockResolvedValue({
   235→          sessionId: BigInt(1),
   236→          status: 'completed',
