   262→        });
   263→      });
   264→    });
   265→
   266→    describe('abortSession', () => {
   267→      it('should mark session as aborted with reason', async () => {
   268→        const sessionId = '1';
   269→        const reason = 'User cancelled batch processing';
   270→
   271→        (mockPrisma.classificationSession.update as jest.Mock).mockResolvedValue({
   272→          sessionId: BigInt(1),
   273→          status: 'aborted',
   274→          finalRationale: reason,
