        expect(metrics.successCount).toBe(95);
        expect(metrics.errorCount).toBe(5);
        expect(metrics.totalDurationMs).toBe(45000);
        expect(metrics.avgEmailDurationMs).toBe(450);
      });

      it('should throw error if metrics not found', async () => {
        (mockPrisma.classificationSessionMetrics.findUnique as jest.Mock).mockResolvedValue(null);

        await expect(repository.getSessionPerformanceStats('999')).rejects.toThrow('Session metrics not found');
      });
    });

    describe('getAverageProcessingTime', () => {
      it('should calculate average processing time across date range', async () => {
        const start = new Date('2025-01-01T00:00:00Z');
        const end = new Date('2025-01-31T23:59:59Z');

        (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([
          {
            sessionId: BigInt(1),
            metrics: { avgEmailDurationMs: { toNumber: () => 400 } },
          },
          {
            sessionId: BigInt(2),
            metrics: { avgEmailDurationMs: { toNumber: () => 600 } },
          },
        ]);

        const avgTime = await repository.getAverageProcessingTime({ start, end });

        expect(avgTime).toBe(500); // (400 + 600) / 2
      });

      it('should return 0 if no sessions in date range', async () => {
        (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([]);

        const avgTime = await repository.getAverageProcessingTime({
          start: new Date(),
          end: new Date(),
        });

        expect(avgTime).toBe(0);
      });
    });

    describe('getFailureRate', () => {
      it('should calculate failure rate as percentage', async () => {
        const start = new Date('2025-01-01T00:00:00Z');
        const end = new Date('2025-01-31T23:59:59Z');

        (mockPrisma.classificationSession.findMany as jest.Mock).mockResolvedValue([
          {
            sessionId: BigInt(1),
            metrics: { emailCount: 100, successCount: 95, errorCount: 5 },
          },
          {
            sessionId: BigInt(2),
            metrics: { emailCount: 50, successCount: 45, errorCount: 5 },
          },
        ]);

        const failureRate = await repository.getFailureRate({ start, end });

        // Total: 150 emails, 10 failures = 6.67%
        expect(failureRate).toBeCloseTo(6.67, 1);
      });
    });
  });

  describe('Error Management', () => {
    describe('getSessionErrors', () => {
      it('should return all errors for a session', async () => {
        const sessionId = '1';

        (mockPrisma.classificationSessionError.findMany as jest.Mock).mockResolvedValue([
          {
            errorId: BigInt(1),
            sessionId: BigInt(1),
            emailId: 'msg-error-001',
            errorType: 'ClassificationError',
            errorMessage: 'Failed to classify',
            stackTrace: 'Error: ...',
            occurredAt: new Date(),
          },
          {
            errorId: BigInt(2),
            sessionId: BigInt(1),
            emailId: 'msg-error-002',
            errorType: 'DatabaseError',
            errorMessage: 'Connection timeout',
            stackTrace: 'Error: ...',
            occurredAt: new Date(),
          },
        ]);

        const errors = await repository.getSessionErrors(sessionId);

        expect(errors).toHaveLength(2);
        expect(errors[0].errorType).toBe('ClassificationError');
        expect(errors[1].errorType).toBe('DatabaseError');
      });
    });
  });

  describe('Constructor and Cleanup', () => {
    it('should create repository with default Prisma client', () => {
      const repo = new SessionRepository();
      expect(repo).toBeInstanceOf(SessionRepository);
    });

    it('should create repository with provided Prisma client', () => {
      const externalPrisma = new PrismaClient();
      const repo = new SessionRepository(externalPrisma);
      expect(repo).toBeInstanceOf(SessionRepository);
    });

    it('should close repository and disconnect Prisma', async () => {
      const repo = new SessionRepository();
      await repo.close();

      expect(mockPrisma.$disconnect).toHaveBeenCalled();
    });
  });
});

