import { PrismaClient, Prisma } from '@prisma/client';
import {
  BatchSessionConfig,
  ProgressUpdate,
  SessionSummary,
  EmailResult,
  SessionDetails,
  SessionStatus,
  PerformanceMetrics,
  BatchProgress,
