/**
 * Session Repository (T044) - Prisma Implementation
 *
 * Repository pattern for session lifecycle management, performance tracking,
 * and analytics queries using Prisma ORM.
 *
 * Separation of Concerns from T043 ClassificationRepository:
 * - T043: Write-heavy classification persistence (commands)
 * - T044: Read-heavy session analytics and lifecycle management (queries)
 *
 * Key Responsibilities:
 * - Session lifecycle management (create, update progress, complete, abort)
 * - Batch processing support (multi-email sessions)
 * - Performance metrics tracking
 * - Error logging and retrieval
 * - Analytics queries (by ID, status, date range, average times, failure rates)
 */

import { PrismaClient, Prisma } from '@prisma/client';
import {
  BatchSessionConfig,
  ProgressUpdate,
  SessionSummary,
  EmailResult,
  SessionDetails,
  SessionStatus,
  PerformanceMetrics,
  BatchProgress,
  SessionError,
  DateRange,
} from '../types/session-types';

/**
 * Session Repository using Prisma ORM
 *
 * Provides session lifecycle management with performance tracking,
 * batch progress monitoring, and analytics queries.
 */
export class SessionRepository {
  private readonly prisma: PrismaClient;
  private readonly ownsPrisma: boolean;

  /**
   * Initialize session repository
   *
   * @param prisma - Optional Prisma client instance (creates default if not provided)
   */
  constructor(prisma?: PrismaClient) {
    if (prisma) {
      this.prisma = prisma;
      this.ownsPrisma = false;
    } else {
      this.prisma = new PrismaClient();
      this.ownsPrisma = true;
    }
  }

  /**
   * Validate and convert session ID from string to BigInt
   *
   * @param sessionId - Session ID as string
   * @returns BigInt representation of session ID
   * @throws {Error} If session ID format is invalid
   */
  private validateAndConvertSessionId(sessionId: string): bigint {
    // Validate format (1-19 digits for safe BigInt conversion)
    if (!/^\d{1,19}$/.test(sessionId)) {
      throw new Error(`Invalid session ID format: ${sessionId}`);
    }

    try {
      return BigInt(sessionId);
    } catch (error) {
      throw new Error(`Failed to parse session ID: ${sessionId}`);
    }
  }

  /**
   * Validate progress update values
   *
   * @param update - Progress update with increment values
   * @throws {Error} If any increment values are negative
   */
  private validateProgressUpdate(update: ProgressUpdate): void {
    if (update.successCount !== undefined && update.successCount < 0) {
      throw new Error('Success count increment must be non-negative');
    }
    if (update.errorCount !== undefined && update.errorCount < 0) {
      throw new Error('Error count increment must be non-negative');
    }
    if (update.parallelStagesCount !== undefined && update.parallelStagesCount < 0) {
      throw new Error('Parallel stages count increment must be non-negative');
    }
    if (update.databaseBatchOps !== undefined && update.databaseBatchOps < 0) {
      throw new Error('Database batch operations increment must be non-negative');
    }
  }

  /**
   * Validate date range
   *
   * @param dateRange - Start and end dates
   * @throws {Error} If date range is invalid
   */
  private validateDateRange(dateRange: DateRange): void {
    if (dateRange.start > dateRange.end) {
      throw new Error(
        `Invalid date range: start (${dateRange.start.toISOString()}) must be before or equal to end (${dateRange.end.toISOString()})`
      );
    }
  }

  /**
   * Create a new batch session with performance tracking
   *
   * Creates both the session record and associated metrics in a transaction.
   * Supports multi-email batch processing.
   *
   * @param config - Batch session configuration
   * @returns Session ID as string (safe representation of bigint)
   * @throws {Error} If session creation fails
   */
  async createBatchSession(config: BatchSessionConfig): Promise<string> {
    try {
      const result = await this.prisma.$transaction(async (tx) => {
        // Create session record
        const session = await tx.classificationSession.create({
          data: {
            gmailId: config.gmailId,
            pipelineVersion: config.pipelineVersion,
            startedAt: new Date(),
            status: 'in_progress',
            triggeredBy: config.triggeredBy || 'system',
            aiRoutingUsed: false,
          },
        });

        // Create metrics record
        await tx.classificationSessionMetrics.create({
          data: {
            sessionId: session.sessionId,
            emailCount: config.batchSize,
            successCount: 0,
            errorCount: 0,
            processingMode: config.processingMode,
            batchSize: config.batchSize,
          },
        });

        return session.sessionId.toString();
      });

      return result;
    } catch (error) {
      throw new Error(`Failed to create batch session: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Update session progress with atomic increments
   *
   * Increments success/error counts and other metrics atomically.
   * Safe for concurrent updates from parallel processing.
   *
   * @param sessionId - Session identifier as string
   * @param update - Progress update with incremental values
   * @throws {Error} If update fails or session not found
   */
  async updateSessionProgress(sessionId: string, update: ProgressUpdate): Promise<void> {
    this.validateProgressUpdate(update);

    try {
      const dbSessionId = this.validateAndConvertSessionId(sessionId);

      // Build update data with atomic increments using proper Prisma type
      const updateData: Prisma.ClassificationSessionMetricsUpdateInput = {
        updatedAt: new Date(),
      };

      if (update.successCount !== undefined) {
        updateData.successCount = { increment: update.successCount };
      }
      if (update.errorCount !== undefined) {
        updateData.errorCount = { increment: update.errorCount };
      }
      if (update.parallelStagesCount !== undefined) {
        updateData.parallelStagesCount = { increment: update.parallelStagesCount };
      }
      if (update.databaseBatchOps !== undefined) {
        updateData.databaseBatchOps = { increment: update.databaseBatchOps };
      }

      await this.prisma.classificationSessionMetrics.update({
        where: { sessionId: dbSessionId },
        data: updateData,
      });
    } catch (error) {
      throw new Error(
        `Failed to update session progress for ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Complete a session with final performance metrics
   *
   * Updates session status to 'completed' and stores final performance metrics.
   * Uses transaction to ensure both session and metrics are updated atomically.
   *
   * @param sessionId - Session identifier as string
   * @param summary - Session summary with performance metrics
   * @throws {Error} If completion fails
   */
  async completeSession(sessionId: string, summary: SessionSummary): Promise<void> {
    try {
      const dbSessionId = this.validateAndConvertSessionId(sessionId);

      await this.prisma.$transaction(async (tx) => {
        // Update session record
        await tx.classificationSession.update({
          where: { sessionId: dbSessionId },
          data: {
            completedAt: new Date(),
            status: 'completed',
            finalCategoryCode: summary.finalCategoryCode || null,
            finalConfidence: summary.finalConfidence ? new Prisma.Decimal(summary.finalConfidence) : null,
            finalRationale: summary.finalRationale || null,
          },
        });

        // Update metrics record
        await tx.classificationSessionMetrics.update({
          where: { sessionId: dbSessionId },
          data: {
            totalDurationMs: summary.totalDurationMs,
            avgEmailDurationMs: summary.avgEmailDurationMs ? new Prisma.Decimal(summary.avgEmailDurationMs) : null,
            peakMemoryMb: summary.peakMemoryMb ? new Prisma.Decimal(summary.peakMemoryMb) : null,
            updatedAt: new Date(),
          },
        });
      });
    } catch (error) {
      throw new Error(
        `Failed to complete session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Abort a session with reason
   *
   * Marks session as 'aborted' and records the reason.
   *
   * @param sessionId - Session identifier as string
   * @param reason - Reason for aborting
   * @throws {Error} If abort fails
   */
  async abortSession(sessionId: string, reason: string): Promise<void> {
    try {
      const dbSessionId = this.validateAndConvertSessionId(sessionId);

      await this.prisma.classificationSession.update({
        where: { sessionId: dbSessionId },
        data: {
          status: 'aborted',
          finalRationale: reason,
          completedAt: new Date(),
        },
      });
    } catch (error) {
      throw new Error(
        `Failed to abort session ${sessionId}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Record result for individual email in batch
   *
   * Increments success/error counts and logs errors for failed emails.
   * Uses transaction to ensure atomic updates.
   *
   * @param sessionId - Session identifier as string
   * @param emailId - Email identifier
   * @param result - Email processing result
   * @throws {Error} If recording fails
   */
  async recordEmailResult(sessionId: string, emailId: string, result: EmailResult): Promise<void> {
    try {
      const dbSessionId = BigInt(sessionId);

      await this.prisma.$transaction(async (tx) => {
        // Update metrics
        if (result.success) {
          await tx.classificationSessionMetrics.update({
            where: { sessionId: dbSessionId },
            data: {
              successCount: { increment: 1 },
              updatedAt: new Date(),
            },
          });
        } else {
          // Increment error count
          await tx.classificationSessionMetrics.update({
            where: { sessionId: dbSessionId },
            data: {
              errorCount: { increment: 1 },
              updatedAt: new Date(),
            },
          });

          // Log error
          if (result.error) {
            await tx.classificationSessionError.create({
              data: {
                sessionId: dbSessionId,
                emailId: emailId,
                errorType: result.error.type,
                errorMessage: result.error.message,
                stackTrace: result.error.stackTrace || null,
              },
            });
          }
        }
      });
    } catch (error) {
      throw new Error(
        `Failed to record email result for ${emailId}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Get batch progress for a session
   *
   * Calculates progress percentage and completion status.
   * Optimized to use single query instead of separate metrics + session queries.
   *
   * @param sessionId - Session identifier as string
   * @returns Batch progress summary
   * @throws {Error} If session not found
   */
  async getBatchProgress(sessionId: string): Promise<BatchProgress> {
    const dbSessionId = BigInt(sessionId);

    // Optimized: Single query with include instead of two separate queries
    const session = await this.prisma.classificationSession.findUnique({
      where: { sessionId: dbSessionId },
      include: { metrics: true },
    });

    if (!session || !session.metrics) {
      throw new Error(`Session not found: ${sessionId}`);
    }

    const metrics = session.metrics;
    const totalProcessed = metrics.successCount + metrics.errorCount;
    const progressPercentage = metrics.emailCount > 0 ? Math.round((totalProcessed / metrics.emailCount) * 100) : 0;

    return {
      sessionId: sessionId,
      totalEmails: metrics.emailCount,
      successCount: metrics.successCount,
      errorCount: metrics.errorCount,
